20	  // Active piece cells (solid)
21	  getPieceCells(type, rotation, x, y).forEach(([r, c]) => {
22	    if (r >= 0 && r < BOARD_ROWS && c >= 0 && c < BOARD_COLS) {
23	      grid[r][c] = { color: PIECES[type].color, ghost: false };
24	    }
